#include <iostream>
#include <cstdlib>
using namespace std;

int main() {
    int n;
    cin >> n;

    // Work with absolute value so sign doesn't matter
    n = abs(n);

    int sum = 0;
    while (n > 0) {
        int digit = n % 10;
        if (digit % 2 == 0) {
            sum += digit;
        }
        n /= 10;
    }

    cout << sum << endl;
    return 0;
}
